insert into wac_birthday_drama_script values (4514066, 4514, 11, '106011', 'ちょちょ、ストーーーップ！！\\nまだろうそく外してないわよ！？\\nほんと相変わらずね、あんたってば……\\nふふっ、おめでと。', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (4514067, 4514, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (4514068, 4514, 3, '106011', 'wac_birthday_idle_doya', '1', '', '', '0.2', '', '');
