insert into wac_birthday_drama_script values (5014055, 5014, 11, '100211', 'この誕生日ケーキ、わたしにっ！？\\nあっ、ありがとう……！\\n……もしかしてこれ、\\nふたりで手作りしてくれたの？', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (5014056, 5014, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (5014057, 5014, 3, '100211', 'wac_birthday_idle_wish', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5014058, 5014, 3, '100311', 'wac_birthday_talk_normal', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5014059, 5014, 21, 'vo_wac_05014', 'vo_wac_05014_001', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (5014060, 5014, 11, '100311', 'うん。私とヒヨリで作ったんだ。\\nユイにはいつだって助けられてるから\\nせめてものお返しだよ。\\n……誕生日おめでとう。ユイ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (5014061, 5014, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (5014062, 5014, 3, '100311', 'wac_birthday_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5014063, 5014, 3, '100211', 'wac_birthday_talk_sad', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5014064, 5014, 21, 'vo_wac_05014', 'vo_wac_05014_002', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (5014065, 5014, 11, '100211', 'そ、そんな……わたしだって、いつも\\n助けられてばっかりで……ご、ごめん！\\nせっかくお祝いしてもらってるのに\\nうれしくて泣いちゃいそう……！', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (5014066, 5014, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (5014067, 5014, 3, '100211', 'wac_birthday_talk_smile', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (5014068, 5014, 21, 'vo_wac_05014', 'vo_wac_05014_003', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (5014069, 5014, 11, '100211', '騎士クンも、本当にありがとうね。\\nみんなに祝福してもらえて\\nわたし、最高に幸せだよ……！\\n大事に味わって食べるね！', '10', '1', '1', '0', '0', '0.5');
