insert into wac_birthday_drama_script values (8014065, 8014, 21, 'vo_wac_08014', 'vo_wac_08014_000', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (8014066, 8014, 11, '104411', 'おお、わらわの誕生日祝いか！\\nうむうむ！\u3000お主らも夜を統べるものの\\n従者としての振る舞いを理解してきた\\nようじゃのう！', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (8014067, 8014, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (8014068, 8014, 3, '104411', 'wac_birthday_idle_normal', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (8014069, 8014, 3, '103111', 'wac_birthday_shinobu_talk_wish', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (8014070, 8014, 21, 'vo_wac_08014', 'vo_wac_08014_002', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (8014071, 8014, 11, '103111', '従者かどうかは\\nちょっとわからないですけど、\\nお祝いしたいと思ったので……\\nお誕生日、おめでとうございます。', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (8014072, 8014, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (8014073, 8014, 3, '103111', 'wac_birthday_shinobu_idle_wish', '1', '', '', '0.2', '', '');
