insert into wac_birthday_drama_script values (8014076, 8014, 11, '104411', 'みなの粋な計らい、褒めてつかわすぞ。\\nお主も駆けつけてくれたのじゃな。\\n我が眷属としての忠勤、大儀である。', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (8014077, 8014, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (8014078, 8014, 3, '104411', 'wac_birthday_talk_smile', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (8014079, 8014, 21, 'vo_wac_08014', 'vo_wac_08014_004', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (8014080, 8014, 11, '104411', 'ふふ。長き時を生きてきたわらわが\\n誕生日で心を動かされるとは……\\n力を取り戻した暁には\\nみなの気持ちにきちんと報いねばのう！', '10', '1', '1', '0', '0', '0.5');
