insert into wac_birthday_drama_script values (8514071, 8514, 11, '102311', 'すっごくうれしいよ！\\nクルミとみんなと、\\nそれにおにいちゃんと……\\n私の大切な人に囲まれて……', '10', '1', '1', '0', '0', '0.5');
