insert into wac_birthday_drama_script values (8614061, 8614, 11, '105911', 'このケーキ……それに飾り付けは……\\nみなさま！\\nわたくしのために、このような……\\nなんとお礼を申し上げれば……', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (8614062, 8614, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (8614063, 8614, 3, '105911', 'wac_birthday_idle_wish', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (8614064, 8614, 3, '106411', 'wac_birthday_talk_normal', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (8614065, 8614, 21, 'vo_wac_08614', 'vo_wac_08614_001', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (8614066, 8614, 11, '106411', '私たちはみんな、同じ食卓を囲む\\n家族なんだから。\\n大事な家族の特別な日を\\nお祝いするのは、当然のことよ。', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (8614067, 8614, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (8614068, 8614, 3, '106411', 'wac_birthday_talk_smile', '1', '', '', '0.2', '', '');
insert into wac_birthday_drama_script values (8614069, 8614, 21, 'vo_wac_08614', 'vo_wac_08614_002', '0', '0', '', '', '', '');
insert into wac_birthday_drama_script values (8614070, 8614, 11, '106411', '改めて、お誕生日おめでとう。\\nコッコロさん！', '10', '1', '1', '0', '0', '0.5');
