insert into wac_birthday_drama_script values (8614075, 8614, 11, '105911', 'シェフィさま……！\\nペコリーヌさまにキャルさま……\\nそれに主さまも。\\n本当に、本当にありがとうございます。', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (8614076, 8614, 91, '0', '', '', '', '', '', '', '');
insert into wac_birthday_drama_script values (8614077, 8614, 3, '105911', 'wac_birthday_talk_smile', '1', '', '', '0.2', '', '');
