insert into wac_birthday_drama_script values (8614079, 8614, 11, '105911', 'みなさまと一緒に、今日という日を、\\nこのような形で迎えられて……\\nわたくしは本当に、\\n果報者でございますね。', '10', '1', '1', '0', '0', '0.5');
