insert into wac_birthday_drama_script values (10914058, 10914, 11, '104211', 'わあ……ありがとうございます。\\nあなたとカルミナのみんなに\\nお祝いしてもらえるなんて……\\nとても嬉しいです♪', '10', '1', '1', '0', '0', '0.5');
