insert into wac_birthday_drama_script values (10914063, 10914, 11, '105411', '私としてはカルミナだけでお祝いしても\\nよかったんですけどね。\\n騎士さんがどうしても一緒に\\nお祝いしたいと言うので……', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (10914064, 10914, 91, '0', '', '', '', '', '', '', '');
