insert into wac_birthday_drama_script values (10914068, 10914, 11, '102911', 'ふふっ、ツムギだって本当は\\nキミが来るのを楽しみにしてたんだよ？\\n私もチカの誕生日をみんなで\\nお祝いできてうれしいよ♪', '10', '1', '1', '0', '0', '0.5');
insert into wac_birthday_drama_script values (10914069, 10914, 91, '0', '', '', '', '', '', '', '');
